import{_ as e,o as a,c as l,ag as n}from"./chunks/framework.BGD3kWga.js";const c=JSON.parse('{"title":"《林峰系统论 · 族》总览","description":"","frontmatter":{"created":"2026-04-25T00:00:00.000Z","tags":["#林峰系统论/族模块","#林峰系统论/总览"]},"headers":[],"relativePath":"02-族模块/02-族模块总览.md","filePath":"02-族模块/02-族模块总览.md"}'),r={name:"02-族模块/02-族模块总览.md"};function s(d,t,i,h,o,g){return a(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="《林峰系统论-·-族》总览" tabindex="-1">《林峰系统论 · 族》总览 <a class="header-anchor" href="#《林峰系统论-·-族》总览" aria-label="Permalink to &quot;《林峰系统论 · 族》总览&quot;">​</a></h1><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><h3 id="层级位置" tabindex="-1">层级位置 <a class="header-anchor" href="#层级位置" aria-label="Permalink to &quot;层级位置&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">上级</th><th style="text-align:left;">本级</th><th style="text-align:left;">下级</th></tr></thead><tbody><tr><td style="text-align:left;">系统论</td><td style="text-align:left;"><strong>族</strong></td><td style="text-align:left;">士、商、工农</td></tr></tbody></table><h3 id="核心内涵" tabindex="-1">核心内涵 <a class="header-anchor" href="#核心内涵" aria-label="Permalink to &quot;核心内涵&quot;">​</a></h3><p>社会治理体系，士商工农协同发展</p><h3 id="模块使命" tabindex="-1">模块使命 <a class="header-anchor" href="#模块使命" aria-label="Permalink to &quot;模块使命&quot;">​</a></h3><p>族模块聚焦社会阶层的协同治理，解析士、商、工农三大阶层的功能定位与协同机制，支撑社会的稳定与发展。</p><hr><h2 id="核心理念" tabindex="-1">核心理念 <a class="header-anchor" href="#核心理念" aria-label="Permalink to &quot;核心理念&quot;">​</a></h2><h3 id="底层逻辑" tabindex="-1">底层逻辑 <a class="header-anchor" href="#底层逻辑" aria-label="Permalink to &quot;底层逻辑&quot;">​</a></h3><p>族模块以**「社会阶层三维度」**为核心框架：</p><table tabindex="0"><thead><tr><th style="text-align:center;">维度</th><th style="text-align:center;">本质属性</th><th style="text-align:center;">核心功能</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>士</strong></td><td style="text-align:center;">智力引领</td><td style="text-align:center;">数据、规划、调度</td></tr><tr><td style="text-align:center;"><strong>商</strong></td><td style="text-align:center;">资源整合</td><td style="text-align:center;">统筹、管理、执行</td></tr><tr><td style="text-align:center;"><strong>工农</strong></td><td style="text-align:center;">基础支撑</td><td style="text-align:center;">总结、实践、学习</td></tr></tbody></table><h3 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><ol><li><strong>阶层协同</strong>：士商工农各司其职、协同发展</li><li><strong>功能互补</strong>：不同阶层发挥各自优势</li><li><strong>动态平衡</strong>：社会阶层结构的动态调整</li><li><strong>共同发展</strong>：各阶层共享发展成果</li></ol><h3 id="研究框架" tabindex="-1">研究框架 <a class="header-anchor" href="#研究框架" aria-label="Permalink to &quot;研究框架&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>族模块</span></span>
<span class="line"><span>├── 士</span></span>
<span class="line"><span>│   ├── 数据：预测、分析、收集</span></span>
<span class="line"><span>│   ├── 规划：高层、中层、底层</span></span>
<span class="line"><span>│   └── 调度：人力、财力、物力</span></span>
<span class="line"><span>├── 商</span></span>
<span class="line"><span>│   ├── 统筹：资源、资产、资金</span></span>
<span class="line"><span>│   ├── 管理：节点、区域、人员</span></span>
<span class="line"><span>│   └── 执行：时间、地点、事情</span></span>
<span class="line"><span>└── 工农</span></span>
<span class="line"><span>    ├── 总结：指导、规划、复盘</span></span>
<span class="line"><span>    ├── 实践：认清、认知、认识</span></span>
<span class="line"><span>    └── 学习：掌握、入门、基础</span></span></code></pre></div><hr><h2 id="模块结构与笔记索引" tabindex="-1">模块结构与笔记索引 <a class="header-anchor" href="#模块结构与笔记索引" aria-label="Permalink to &quot;模块结构与笔记索引&quot;">​</a></h2><h3 id="二级结构-三大阶层" tabindex="-1">二级结构：三大阶层 <a class="header-anchor" href="#二级结构-三大阶层" aria-label="Permalink to &quot;二级结构：三大阶层&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">编号</th><th style="text-align:center;">阶层</th><th style="text-align:left;">核心内涵</th><th style="text-align:center;">关联笔记</th></tr></thead><tbody><tr><td style="text-align:center;">02-01</td><td style="text-align:center;">[[02-01-士|士]]</td><td style="text-align:left;">智力引领阶层，负责数据、规划、调度</td><td style="text-align:center;">[[02-01-士]]</td></tr><tr><td style="text-align:center;">02-02</td><td style="text-align:center;">[[02-02-商|商]]</td><td style="text-align:left;">资源整合阶层，负责统筹、管理、执行</td><td style="text-align:center;">[[02-02-商]]</td></tr><tr><td style="text-align:center;">02-03</td><td style="text-align:center;">[[02-03-工农|工农]]</td><td style="text-align:left;">基础支撑阶层，负责总结、实践、学习</td><td style="text-align:center;">[[02-03-工农]]</td></tr></tbody></table><hr><h2 id="关键概念术语表" tabindex="-1">关键概念术语表 <a class="header-anchor" href="#关键概念术语表" aria-label="Permalink to &quot;关键概念术语表&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">术语</th><th style="text-align:left;">定义</th><th style="text-align:center;">关联笔记</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>士</strong></td><td style="text-align:left;">智力引领阶层，负责数据、规划、调度</td><td style="text-align:center;">[[02-01-士]]</td></tr><tr><td style="text-align:center;"><strong>商</strong></td><td style="text-align:left;">资源整合阶层，负责统筹、管理、执行</td><td style="text-align:center;">[[02-02-商]]</td></tr><tr><td style="text-align:center;"><strong>工农</strong></td><td style="text-align:left;">基础支撑阶层，负责总结、实践、学习</td><td style="text-align:center;">[[02-03-工农]]</td></tr><tr><td style="text-align:center;"><strong>阶层协同</strong></td><td style="text-align:left;">不同社会阶层的协作与配合</td><td style="text-align:center;">族模块</td></tr><tr><td style="text-align:center;"><strong>社会治理</strong></td><td style="text-align:left;">社会各阶层共同参与的治理模式</td><td style="text-align:center;">族模块</td></tr></tbody></table><hr><h2 id="模块关联分析" tabindex="-1">模块关联分析 <a class="header-anchor" href="#模块关联分析" aria-label="Permalink to &quot;模块关联分析&quot;">​</a></h2><h3 id="与同级模块的关联" tabindex="-1">与同级模块的关联 <a class="header-anchor" href="#与同级模块的关联" aria-label="Permalink to &quot;与同级模块的关联&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">关联模块</th><th style="text-align:left;">族→关联模块</th><th style="text-align:left;">关联模块→族</th></tr></thead><tbody><tr><td style="text-align:left;">国</td><td style="text-align:left;">族是国的社会基础</td><td style="text-align:left;">国为族提供发展环境</td></tr><tr><td style="text-align:left;">家</td><td style="text-align:left;">族是家的社会网络</td><td style="text-align:left;">家是族的基本单元</td></tr><tr><td style="text-align:left;">企</td><td style="text-align:left;">商是企的核心要素</td><td style="text-align:left;">企为商提供发展平台</td></tr></tbody></table><h3 id="与其他层级模块的关联" tabindex="-1">与其他层级模块的关联 <a class="header-anchor" href="#与其他层级模块的关联" aria-label="Permalink to &quot;与其他层级模块的关联&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">关联层级</th><th style="text-align:left;">关系说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>士（数据）</strong></td><td style="text-align:left;">数据为决策提供依据</td></tr><tr><td style="text-align:left;"><strong>商（统筹）</strong></td><td style="text-align:left;">统筹整合社会资源</td></tr><tr><td style="text-align:left;"><strong>工农（实践）</strong></td><td style="text-align:left;">实践创造物质财富</td></tr></tbody></table><hr><h2 id="模块迭代计划" tabindex="-1">模块迭代计划 <a class="header-anchor" href="#模块迭代计划" aria-label="Permalink to &quot;模块迭代计划&quot;">​</a></h2><h3 id="优先级排序" tabindex="-1">优先级排序 <a class="header-anchor" href="#优先级排序" aria-label="Permalink to &quot;优先级排序&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">优先级</th><th style="text-align:left;">事项</th><th style="text-align:left;">说明</th><th style="text-align:center;">状态</th></tr></thead><tbody><tr><td style="text-align:center;">P0</td><td style="text-align:left;">生成士、商、工农二级总览</td><td style="text-align:left;">完善族模块结构</td><td style="text-align:center;">待启动</td></tr><tr><td style="text-align:center;">P1</td><td style="text-align:left;">生成三级主题总览</td><td style="text-align:left;">数据/规划/调度等9个主题</td><td style="text-align:center;">待启动</td></tr><tr><td style="text-align:center;">P2</td><td style="text-align:left;">生成四级具体领域总览</td><td style="text-align:left;">数据预测/分析/收集等27个领域</td><td style="text-align:center;">待启动</td></tr></tbody></table><h3 id="待办事项" tabindex="-1">待办事项 <a class="header-anchor" href="#待办事项" aria-label="Permalink to &quot;待办事项&quot;">​</a></h3><ul><li>[ ] 生成 [[02-01-士总览]] 等三个二级总览</li><li>[ ] 生成 [[02-01-01-数据总览]] 等九个三级总览</li><li>[ ] 生成 [[02-01-01-01-数据预测总览]] 等二十七个四级总览</li></ul><h3 id="研究方向" tabindex="-1">研究方向 <a class="header-anchor" href="#研究方向" aria-label="Permalink to &quot;研究方向&quot;">​</a></h3><ol><li><strong>阶层流动</strong>：社会阶层的流动机制</li><li><strong>协同治理</strong>：多阶层协同的治理模式</li><li><strong>共同富裕</strong>：各阶层共享发展成果</li><li><strong>社会稳定</strong>：阶层结构的动态平衡</li></ol><hr><h2 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h2><h3 id="文件元信息" tabindex="-1">文件元信息 <a class="header-anchor" href="#文件元信息" aria-label="Permalink to &quot;文件元信息&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;">模块名称</td><td style="text-align:left;">族</td></tr><tr><td style="text-align:left;">模块编号</td><td style="text-align:left;">02</td></tr><tr><td style="text-align:left;">上级模块</td><td style="text-align:left;">系统论</td></tr><tr><td style="text-align:left;">创建日期</td><td style="text-align:left;">2026-04-25</td></tr><tr><td style="text-align:left;">文档版本</td><td style="text-align:left;">V1.0</td></tr></tbody></table><h3 id="修订历史" tabindex="-1">修订历史 <a class="header-anchor" href="#修订历史" aria-label="Permalink to &quot;修订历史&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">版本</th><th style="text-align:center;">日期</th><th style="text-align:left;">修订内容</th></tr></thead><tbody><tr><td style="text-align:center;">V1.0</td><td style="text-align:center;">2026-04-25</td><td style="text-align:left;">初始生成总览文档</td></tr></tbody></table>`,44)])])}const y=e(r,[["render",s]]);export{c as __pageData,y as default};
